digraph ProgramFlow {
    rankdir=TB;
    node [shape=box, style=rounded];

    subgraph cluster_main {
        label="Initialization Block (MAIN)";
        style=filled;
        color=lightgrey;

        main1 [label="TMOD ← 0x10 (Timer1 mode 1)"];
        main2 [label="TH1 ← 0xFF, TL1 ← 0x31"];
        main3 [label="TR1 ← 1 (start timer)"];
        main4 [label="ET1 ← 1, EA ← 1 (enable interrupts)"];
        main5 [label="Infinite loop (SJMP $)"];

        main1 -> main2 -> main3 -> main4 -> main5;
    }

    subgraph cluster_isr {
        label="Interrupt Service Routine (T1_ISR)";
        style=filled;
        color=lightblue;

        isr1 [label="P2.3 ← NOT(P2.3) (toggle)"];
        isr2 [label="TH1 ← 0xFF, TL1 ← 0x31 (reload timer)"];
        isr3 [label="RETI (return to main loop)"];

        isr1 -> isr2 -> isr3;
    }

    main5 -> isr1 [label="Timer1 overflow interrupt", style=dashed, color=red];
    isr3 -> main5 [label="Return", style=dashed, color=green];
}

digraph {
    rankdir=TB;
    node [shape=box, style=rounded];
    Start [label="Start"];
    Init [label="Initialize Serial (TMOD, TH1, SCON, TR1)"];
    LOOP [label="LOOP:"];
    WaitRI [label="Wait for RI"];
    RI0 [label="RI = 0?", shape=diamond];
    RI1 [label="RI = 1"];
    ReadSBUF [label="Read SBUF → A"];
    ClearRI [label="Clear RI"];
    TestACC0 [label="Test ACC.0", shape=diamond];
    SendP1 [label="Send A → P1"];
    SendP2 [label="Send A → P2"];
    JumpLOOP [label="Jump to LOOP"];

    Start -> Init;
    Init -> LOOP;
    LOOP -> WaitRI;
    WaitRI -> RI0;
    RI0 -> WaitRI [label="Yes"];
    RI0 -> RI1 [label="No"];
    RI1 -> ReadSBUF;
    ReadSBUF -> ClearRI;
    ClearRI -> TestACC0;
    TestACC0 -> SendP1 [label="0"];
    TestACC0 -> SendP2 [label="1"];
    SendP1 -> JumpLOOP;
    SendP2 -> JumpLOOP;
    JumpLOOP -> LOOP;
}

digraph architecture {
    rankdir=LR;
    node [shape=box, style=filled, fillcolor=lightgray];

    CPU [label="CPU Core (8051)", shape=ellipse, fillcolor=lightblue];
    P0 [label="Port P0\nInput", fillcolor=lightgreen];
    P1 [label="Port P1\nOutput\n(P1.4 = Buzzer)", fillcolor=lightgreen];
    UART [label="Serial Port (UART)\n2400 baud, 'VIT' string", fillcolor=lightyellow];
    INT1 [label="INT1 (P3.3)\nFalling Edge Trigger", fillcolor=lightcoral];
    Timer0 [label="Timer 0\n500ms Delay", fillcolor=lightpink];
    Timer1 [label="Timer 1\nBaud Rate Gen", fillcolor=lightpink];
    Memory [label="Memory Map\nCode: 0000H\nVectors: Designated\nVars: 20H-7FH", fillcolor=lightcyan];

    P0 -> CPU [label="Solid line\nContinuous", style=solid];
    CPU -> P1 [label="Solid line\nContinuous", style=solid];
    CPU -> UART [label="Tx", style=solid];
    INT1 -> CPU [label="Dashed line\nInterrupt", style=dashed];
    Timer0 -> CPU [label="Dashed line\nInterrupt", style=dashed];
    UART -> CPU [label="Dashed line\nInterrupt", style=dashed];
    Timer1 -> UART [label="Dotted line\nTimer Overflow", style=dotted];
    Timer0 -> CPU [label="Dotted line\nTimer Overflow", style=dotted];
    CPU -> Memory [label="Access", style=solid];
}

digraph {
    rankdir=TB;
    node [shape=box, style=filled, fillcolor=lightgray];
    edge [arrowhead=normal];

    MAIN [label="MAIN PROGRAM\n- Initialize TCON, IE\n- Set LED initial OFF\n- Infinite loop"];
    ISR_INT0 [label="ISR_INT0\nCLR P1.3\n(LED ON)"];
    ISR_INT1 [label="ISR_INT1\nSETB P1.3\n(LED OFF)"];
    RETURN [label="Return to Main Loop"];

    MAIN -> ISR_INT0 [label="INT0 trigger (↓)\n(P3.2 falling edge)"];
    MAIN -> ISR_INT1 [label="INT1 trigger (↓)\n(P3.3 falling edge)"];
    ISR_INT0 -> RETURN;
    ISR_INT1 -> RETURN;
    RETURN -> MAIN [style=dashed];
}

digraph G {
    rankdir=LR;
    node [shape=box, style=rounded];

    subgraph cluster_mcu {
        label="AT89C51";
        style=filled;
        color=lightgrey;

        node [shape=ellipse];
        crystal [label="12 MHz Crystal\nXTAL1 XTAL2"];
        timer0 [label="Timer 0 (Mode 2)\nTH0 = 0x9C\nInterrupt: 000BH"];
        timer1 [label="Timer 1 (Mode 2)\nTH1 = 0x38\nInterrupt: 001BH"];
        int_controller [label="Interrupt Controller"];

        crystal -> timer0 [style=invis];
        crystal -> timer1 [style=invis];
        timer0 -> int_controller [label="Overflow"];
        timer1 -> int_controller [label="Overflow"];
    }

    subgraph cluster_isr {
        label="ISR Execution";
        style=filled;
        color=lightblue;

        isr0 [label="TIMER0_ISR\n(CPL P1.0)"];
        isr1 [label="TIMER1_ISR\n(CPL P1.1)"];

        int_controller -> isr0;
        int_controller -> isr1;
    }

    pin_toggle [label="Pin Toggling", shape=box];
    isr0 -> pin_toggle;
    isr1 -> pin_toggle;

    output [label="Square Waves on P1.0, P1.1", shape=box];
    pin_toggle -> output;

    waveform1 [label="P1.0 (Waveform 1)\n0.1 ms ON/OFF", shape=ellipse];
    waveform2 [label="P1.1 (Waveform 2)\n0.2 ms ON/OFF", shape=ellipse];

    timer0 -> waveform1 [label="Output"];
    timer1 -> waveform2 [label="Output"];
    output -> waveform1 [style=invis];
    output -> waveform2 [style=invis];
}
